ee:message.ee:set-payload:
%dw 2.0
output application/json
// ---------- Query params ----------
var zipParam        = attributes.queryParams.zip         default ""
var menopause       = (attributes.queryParams.menopause  default "false") == "true"
var limitParam      = attributes.queryParams.limit       default "10"
var limitN          = limitParam as Number default 10
var fallbackEnabled = (attributes.queryParams.fallback   default "false") == "true"
// Insurance plan token. Synonym normalization (United → uhc etc.) is the
// route handler's job today; the live worker accepts the canonical token
// or whatever lowercase string the caller passed and does an exact-match
// containment check against insuranceAccepted.
var insuranceQ      = lower(attributes.queryParams.insurance default "")

// ---------- Static directory slice ----------
// Curated rows pulled from the committed
// frontend/lib/provider-directory.generated.json so every demo persona
// resolves to a real certified-local provider and we have at least one
// relevant-local + one certified-remote example for the fallback ladder.
// New states / personas extend this list; the contract logic below is
// data-shape-independent.
var allProviders = [
  {
    npi: "1730155570",
    name: "Dr. Priya Anand, MD, FACOG, MSCP",
    credentials: ["MD", "FACOG", "MSCP"],
    specialty: "Obstetrics & Gynecology",
    menopauseCertified: true,
    city: "Irvine", state: "CA", zip: "92614",
    acceptingNewPatients: false, telehealth: false,
    graphScore: 0.7624,
    latitude: 33.68021, longitude: -117.833355,
    serviceSignals: ["facog"],
    licenseStatus: "active",
    insuranceAccepted: ["medicare", "medicaid", "aetna", "cigna"]
  },
  {
