    credentials: ["DO", "MSCP"],
    specialty: "Endocrinology, Diabetes & Metabolism",
    menopauseCertified: true,
    city: "Newport Beach", state: "CA", zip: "92660",
    acceptingNewPatients: true, telehealth: true,
