    latitude: 33.634626, longitude: -117.874882,
    serviceSignals: ["multi-taxonomy"],
    licenseStatus: "active",
    insuranceAccepted: ["medicare", "medicaid", "aetna", "humana", "kaiser"]
  },
  {
