    credentials: ["NP", "MSCP"],
    specialty: "Nurse Practitioner — Women's Health",
    menopauseCertified: true,
    city: "Brooklyn", state: "NY", zip: "11215",
    acceptingNewPatients: false, telehealth: false,
    graphScore: 0.6716,
    latitude: 40.662688, longitude: -73.98674,
    serviceSignals: [],
    licenseStatus: "active",
    insuranceAccepted: ["medicare", "medicaid", "aetna", "bcbs", "uhc"]
  },
  {
    npi: "1922450088",
    name: "Dr. Samuel Levin, MD, MSCP",
    credentials: ["MD", "MSCP"],
    specialty: "Endocrinology, Diabetes & Metabolism",
    menopauseCertified: true,
    city: "New York", state: "NY", zip: "10024",
    acceptingNewPatients: true, telehealth: true,
    graphScore: 1.0,
    latitude: 40.798452, longitude: -73.974414,
    serviceSignals: [],
    licenseStatus: "active",
    insuranceAccepted: ["medicare", "medicaid", "aetna", "bcbs"]
  },
  {
    npi: "1134567890",
    name: "Dr. Rina Patel, CNM, MSCP",
    credentials: ["CNM", "MSCP"],
    specialty: "Certified Nurse-Midwife (Lactation)",
    menopauseCertified: true,
    city: "Los Angeles", state: "CA", zip: "90012",
    acceptingNewPatients: true, telehealth: false,
    graphScore: 0.868,
    latitude: 34.065975, longitude: -118.238642,
    serviceSignals: ["cnm"],
    licenseStatus: "active",
    insuranceAccepted: ["medicare", "medicaid", "aetna", "bcbs", "uhc"]
  },
  {
    npi: "1356789012",
    name: "Dr. Megan Sullivan, MD, FAAFP, MSCP",
    credentials: ["MD", "FAAFP", "MSCP"],
