    acceptingNewPatients: true, telehealth: true,
    graphScore: 1.0,
    latitude: 40.632667, longitude: -73.996669,
    serviceSignals: [],
    licenseStatus: "active",
    insuranceAccepted: ["aetna", "bcbs", "cigna"]
  }
]

// ---------- Filter helpers ----------
// 3-digit ZIP-prefix predicate. Empty / short query ZIP → no narrowing.
fun inArea(p, q) = sizeOf(q) < 3 or p.zip[0 to 2] == q[0 to 2]
// Insurance filter — exact-match containment. When the query is empty
// every row passes (the filter is opt-in).
fun acceptsPlan(p, q) = sizeOf(q) == 0 or (p.insuranceAccepted contains q)

// Insurance filter applied BEFORE the tier ladder so all tiers honor it.
var pool = allProviders filter acceptsPlan($, insuranceQ)

// ---------- Tier ladder ----------
// certified-local → certified-national (no zip given) →
// relevant-local (fallback only) → certified-remote (fallback only) →
// none. Mirrors queryProviderDirectory in mulesoft-mocks.ts.
var prefix = if (sizeOf(zipParam) >= 3) zipParam[0 to 2] else ""

var tier = if (!menopause) (
  if (sizeOf(prefix) > 0) {
    rows: pool filter inArea($, zipParam),
    matchType: "local"
  } else {
    rows: pool,
    matchType: "all"
  }
) else if (sizeOf(prefix) == 0) {
  // certified-national: no ZIP given.
  rows: pool filter $.menopauseCertified == true,
  matchType: "certified-national"
} else (do {
  var certifiedLocal = pool filter ($.menopauseCertified == true and inArea($, zipParam))
  ---
  if (sizeOf(certifiedLocal) > 0) {
    rows: certifiedLocal,
    matchType: "certified-local"
  } else if (!fallbackEnabled) {
    // Strict default: empty result rather than broadening behind the
    // caller's back. The route handler sets ?fallback=true for the
    // agent-facing path so the agent gets a usable answer.
    rows: certifiedLocal,
    matchType: "certified-local"
  } else (do {
    var relevantLocal = pool filter ($.menopauseCertified == false and inArea($, zipParam))
    ---
    if (sizeOf(relevantLocal) > 0) {
      rows: relevantLocal,
      matchType: "relevant-local"
    } else (do {
      var certifiedTele = pool filter ($.menopauseCertified == true and $.telehealth == true)
      var anyCertified  = pool filter $.menopauseCertified == true
      ---
      {
        rows: if (sizeOf(certifiedTele) > 0) certifiedTele else anyCertified,
        matchType: "certified-remote"
      }
    })
  })
})

// Distance ranking — the live worker doesn't carry the ZCTA centroid table
// for the patient ZIP, so it can't compute Haversine miles here. The mock's
// contract honors `sort: "score"` + `distanceMiles: null` as the graceful
// fallback in this case; the route handler runs the centroid resolution on
// the way out when callers want distance. Each row still carries
// `distanceMiles: null` so the response shape is field-complete.
var sortedRows = (tier.rows orderBy -$.graphScore) map ((r) -> r ++ { distanceMiles: null })
var totalRows  = sizeOf(sortedRows)
var clamped    = if (totalRows < limitN) totalRows else limitN
var resultRows = if (clamped == 0) [] else sortedRows[0 to (clamped - 1)]
var finalMatchType = if (totalRows == 0) "none" else tier.matchType
---
{
  query: {
    zip:           if (sizeOf(zipParam) > 0) zipParam else null,
    menopauseOnly: menopause,
    limit:         limitN,
    fallback:      fallbackEnabled,
    insurance:     if (sizeOf(insuranceQ) > 0) insuranceQ else null
  },
  matchType: finalMatchType,
  sort: "score",
  'total':  totalRows,
  returned: sizeOf(resultRows),
  providers: resultRows,
  provenance: {
    sources: [
      "CMS NPPES (taxonomy-filtered slice baked into MuleSoft worker)",
      "Self-reported MSCP/NCMP credentials + curated overlay",
      "Insurance acceptance is synthetically derived per-NPI (no public payer feed; replace with a real partner feed when available)"
    ],
    experienceApi: "pause-provider-directory-experience-api@0.9",
    servedBy: "mulesoft-cloudhub2",
    dataset: {
      generatedAt: null,
      sourceDate: null,
      total: sizeOf(allProviders),
      certified: sizeOf(allProviders filter $.menopauseCertified == true),
      states: sizeOf((allProviders.state default []) distinctBy $),
      zip3Prefixes: sizeOf((allProviders map $.zip[0 to 2]) distinctBy $),
      sanctionedFiltered: 0,
      sanctionedFilteredBySource: {},
      sanctionsOverlaysUsed: {}
    }
  }
}
